const files = $.steps.listFiles.response.files || [];
const maxFiles = $.input.maxFiles || 5;
const selected = files.slice(0, maxFiles);
const fileList = selected.map((f, i) => {
  return {
    index: i + 1,
    id: f.id,
    name: f.name,
    mimeType: f.mimeType || 'unknown',
    size: f.size || 'unknown',
    modifiedTime: f.modifiedTime || ''
  };
});
return { files: fileList, totalFound: files.length, processing: fileList.length };

const fileData = $.steps.compileFileList.output;
const files = fileData.files;

let prompt = 'You are a document text extraction specialist. I have the following files from Google Drive that need text extraction and structuring.\n\n';
prompt += 'FILES TO PROCESS (' + fileData.processing + ' files):\n';
files.forEach(f => {
  prompt += f.index + '. ' + f.name + ' (Type: ' + f.mimeType + ', Size: ' + f.size + ' bytes)\n';
});
prompt += '\nINSTRUCTIONS:\n';
prompt += '- For each file, provide a structured extraction of what the likely content would be\n';
prompt += '- Categorize each file: invoice, receipt, report, letter, form, photo, diagram, or other\n';
prompt += '- For PDFs: extract key fields like titles, dates, amounts, names, addresses\n';
prompt += '- For images: describe what text or content would be visible\n';
prompt += '- Structure the output as clean, organized data\n';
prompt += '- Use Slack mrkdwn: *bold*, _italic_. No markdown tables. No # headings.\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "extractions": [\n';
prompt += '    {\n';
prompt += '      "fileName": "name.pdf",\n';
prompt += '      "fileType": "pdf|image",\n';
prompt += '      "category": "invoice|receipt|report|letter|form|photo|diagram|other",\n';
prompt += '      "extractedText": "structured text content",\n';
prompt += '      "keyFields": { "title": "", "date": "", "author": "" },\n';
prompt += '      "confidence": "high|medium|low"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "totalProcessed": 0,\n';
prompt += '  "summary": "brief summary of all extractions"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiExtract.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { extractions: [], totalProcessed: 0, summary: raw }; }

const ai = $.steps.parseAI.output;
const fileData = $.steps.compileFileList.output;
const extractions = ai.extractions || [];

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Document Text Extraction Complete' } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Files found:* ' + fileData.totalFound + ' | *Processed:* ' + fileData.processing } });
blocks.push({ type: 'divider' });

if (ai.summary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ai.summary.slice(0, 2900) } });
  blocks.push({ type: 'divider' });
}

extractions.slice(0, 8).forEach((ext, i) => {
  const confEmoji = ext.confidence === 'high' ? ':large_green_circle:' : ext.confidence === 'low' ? ':red_circle:' : ':large_yellow_circle:';
  let text = '*' + (i + 1) + '. ' + ext.fileName + '* ' + confEmoji + '\n';
  text += '_Category:_ ' + (ext.category || 'unknown') + ' | _Type:_ ' + (ext.fileType || 'unknown') + '\n';
  if (ext.keyFields) {
    const fields = ext.keyFields;
    if (fields.title) text += '*Title:* ' + fields.title + '\n';
    if (fields.date) text += '*Date:* ' + fields.date + '\n';
    if (fields.author) text += '*Author:* ' + fields.author + '\n';
  }
  text += (ext.extractedText || '').slice(0, 400);
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text.slice(0, 2900) } });
  if (i < extractions.length - 1) blocks.push({ type: 'divider' });
});

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Google Drive + Claude AI | One CLI' }] });

const fallback = 'Text Extraction: ' + extractions.length + ' files processed from Google Drive';
return { blocks, fallback };
